  ('aboriginal-e3452428-moex-00031', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3a7b2121', 'sub-aboriginal-e3452428-02', NULL, 'single_choice', '民間成立保全公司以協助警方維護治安，屬於下列何種公共服務提供模式？', '["租稅優惠", "無償移轉", "權力集中", "功能替代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "993af577e152", "answer_pdf_sha1": "8fdcf3236bdf", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00032', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律之敘述，下列何者錯誤？', '["所謂法律，原則上係對不特定人之權利義務所為之抽象規定", "預算案實質上為行政行為之一種，但因具有法律之形式，故稱之為措施性法律", "若法律實際適用結果，僅單一或少數對象受該法律規範者，即為憲法所不許", "法律明確性原則並無禁止立法者衡酌生活事實之複雜性及適用於個案之妥當性，適當運用不確 定法律概念之可能性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00033', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於法律不溯及既往原則之敘述，下列何者錯誤？', '["不論負擔性或授益性法律均有法律不溯及既往之適用", "真正溯及既往係指，法規於時間上向前適用於已確定終結之案件", "原則上法律不溯及既往只禁止真正溯及既往之情形，惟若不真正溯及既往之影響過鉅，則宜制 定過渡條款", "基於重大公益之考量仍可能例外允許制定真正溯及既往之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00034', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何者非屬不確定法律概念？', '["食品安全衛生管理法第15條之「有毒或含有害人體健康之物質或異物」", "建築法第58條之「危害公共安全者」", "空氣污染防制法第62條之「通知限期補正或改善」", "廢棄物清理法第2條之「有害事業廢棄物」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00035', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於公立中小學與學生之法律關係，下列敘述何者正確？', '["學校不得對學生作成行政處分", "學生與學校成立公法上之營造物利用關係", "學校制定學生退學之校規，無需任何法律依據", "學生與學校間之營造物利用關係發生爭執時，僅得透過家長會協議解決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00036', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何者為行政法人？', '["國立故宮博物院", "中央銀行", "國家中山科學研究院", "公平交易委員會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00037', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於行政機關管轄權限之變更，下列敘述何者正確？', '["行政機關依法規委任所屬下級機關執行事務，不需要公告及刊登政府公報或新聞紙", "除有法律明文規定，否則行政機關不得將其權限之一部委託民間團體辦理", "行政機關得僅依行政程序法第15條第2項規定，將其權限委託不相隸屬之行政機關", "行政機關依法規將其權限之一部分，委託民間團體辦理，該民間團體於委託範圍內，視為行政 機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00038', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '甲為行政院所屬薦任八職等之公務員，有關將甲移送懲戒之敘述，下列何者錯誤？', '["甲之非執行職務之違法行為，如嚴重損害政府信譽，亦得移送懲戒", "行政院就甲之失職行為，得不經彈劾程序，逕送懲戒法院審理", "監察院對於甲之失職行為，得主動調查，並於彈劾後移送懲戒法院審理", "如甲之失職行為應受免除職務之懲戒處分，而該行為終了已逾 10 年，行政院即無法再將甲移 送懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00039', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '公務人員對於服務機關或人事主管機關所為下列人事行政行為，何者不得提起復審？', '["評定試用成績不及格", "機關組成性騷擾處理委員會作成性騷擾成立與否之決定", "申誡之懲處", "核定現職人員部分辦公時間進修 50750、51050"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00040', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-114-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何種身分不適用公務員服務法？', '["受主管機關指派於公營事業擔任董事者", "執行政府委託研究案之國立大學教授", "縣立小學兼任總務主任之教師", "現役軍士官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:56+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL)
